#include <stdio.h>

int main() {
    int e,n,ans=0;
    scanf("%d%d",&e,&n);
    int max=e>n?e:n;
    int min=e<n?e:n;
    if(max>=2*min)
    {
        printf("%d",min);
    }
    else
    {
        int ans=(e+n)/3;
        printf("%d",ans);
    }
    return 0;
}

